package main

import (
    "fmt"
    "math/rand"
    "time"

    cr "crypto/rand" // aliased import
    "encoding/hex"
)

func main() {
    // Standard library
    fmt.Println("Random:", rand.Intn(100))

    // Crypto random via alias
    b := make([]byte, 4)
    cr.Read(b)
    fmt.Println("Crypto random:", hex.EncodeToString(b))

    // Time seeded random
    rand.Seed(time.Now().UnixNano())
    fmt.Println("Seeded:", rand.Intn(100))
}
